import { cursor } from './cursor';
import { userGrid } from './grid';
import { derived, writable } from 'svelte/store';

const gamePaused = writable(true);

export const keyboardDisabled = derived(
	[cursor, userGrid, gamePaused],
	([$cursor, $userGrid, $gamePaused]) => {
		if (!$cursor || !$userGrid) return true;
		const x = $cursor.x;
		const y = $cursor.y;
		return (x === null && y === null) || ($userGrid[y] && $userGrid[y][x] !== 0) || $gamePaused;
	},
	true,
);